import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        int count = input.nextInt();
        double measurement = input.nextDouble();
        System.out.printf("%d %.1f%n", count + 1, measurement + 0.5);
    }
}
